export const getById = (id: number) => PRODUCTS.find(p => p.id === id);
export const getByType = (type: string) => PRODUCTS.filter(p => p.type === type);
export const discPct = (p: Product) => Math.round((p.price - p.disc) / p.price * 100);
export const getCatConf = (type: string) => CATEGORIES.find(c => c.type === type);

